/**
 * Admin calendar — week grid: rows = teachers, columns = days, cells = slots.
 * Filters by week + status. Click slot → detail popover.
 */

import { useEffect, useMemo, useState } from 'react'
import PlatformShell from '../components/PlatformShell'
import { useToast } from '../hooks/useToast'
import { fetchAllSlots, updateSlotStatus, type SlotDto } from '../api/schedule'
import { generateSlots } from '../api/availability'

const DAYS = ['Пн', 'Вт', 'Ср', 'Чт', 'Пт', 'Сб', 'Вс']

const STATUS_COLOR: Record<string, string> = {
  scheduled:  '#A9D8FF',
  conducted:  '#9FE8C7',
  cancelled:  '#FFB4C8',
  transferred:'#FFD43C',
}

function startOfWeek(d: Date): Date {
  const r = new Date(d)
  const day = r.getDay()
  const diff = (day === 0 ? -6 : 1 - day)
  r.setDate(r.getDate() + diff)
  r.setHours(0, 0, 0, 0)
  return r
}

function fmtIsoDate(d: Date): string {
  return d.toISOString().slice(0, 10)
}

export default function AdminCalendar() {
  const { toast, show } = useToast()
  const [weekStart, setWeekStart] = useState(() => startOfWeek(new Date()))
  const [slots, setSlots] = useState<SlotDto[]>([])
  const [loading, setLoading] = useState(false)
  const [active, setActive] = useState<SlotDto | null>(null)
  const [generating, setGenerating] = useState(false)

  const weekEnd = useMemo(() => {
    const d = new Date(weekStart)
    d.setDate(d.getDate() + 7)
    return d
  }, [weekStart])

  function load() {
    setLoading(true)
    fetchAllSlots(weekStart.toISOString(), weekEnd.toISOString())
      .then(setSlots)
      .catch(() => show('Ошибка загрузки', 'error'))
      .finally(() => setLoading(false))
  }

  useEffect(load, [weekStart])

  // teachers grouped, slots by (teacherId, dayIndex)
  const grouped = useMemo(() => {
    const map = new Map<string, Map<number, SlotDto[]>>()
    for (const s of slots) {
      const dt = new Date(s.datetime)
      const dayIdx = (dt.getDay() + 6) % 7  // Mon=0 … Sun=6
      const tmap = map.get(s.teacherId) ?? new Map<number, SlotDto[]>()
      const arr = tmap.get(dayIdx) ?? []
      arr.push(s)
      tmap.set(dayIdx, arr)
      map.set(s.teacherId, tmap)
    }
    return Array.from(map.entries())
  }, [slots])

  function shiftWeek(deltaDays: number) {
    const d = new Date(weekStart)
    d.setDate(d.getDate() + deltaDays)
    setWeekStart(startOfWeek(d))
  }

  async function handleCancel(slot: SlotDto) {
    try {
      await updateSlotStatus(slot.id, 'cancelled')
      show('Слот отменён', 'success')
      setActive(null)
      load()
    } catch (e) {
      show('Ошибка: ' + (e instanceof Error ? e.message : ''), 'error')
    }
  }

  async function handleGenerate() {
    setGenerating(true)
    try {
      const res = await generateSlots(fmtIsoDate(weekStart), fmtIsoDate(weekEnd))
      show(`Создано ${res.created}, пропущено ${res.skipped}`, 'success')
      load()
    } catch (e) {
      show('Ошибка генерации: ' + (e instanceof Error ? e.message : ''), 'error')
    } finally {
      setGenerating(false)
    }
  }

  return (
    <PlatformShell activeKey="admin">
      {toast && (
        <div role="status" style={{ position: 'fixed', top: 20, right: 20, zIndex: 9999, background: toast.kind === 'error' ? '#dc2626' : toast.kind === 'success' ? '#059669' : '#6b5ce7', color: '#fff', padding: '10px 20px', borderRadius: 12, fontSize: 14, fontWeight: 600 }}>{toast.msg}</div>
      )}

      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>📆</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Календарь</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>
              {weekStart.toLocaleDateString('ru-RU', { day: 'numeric', month: 'long' })} — {new Date(weekEnd.getTime() - 86_400_000).toLocaleDateString('ru-RU', { day: 'numeric', month: 'long' })}
            </h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 1400, margin: '0 auto', padding: '20px 16px' }}>
        <div style={{ display: 'flex', gap: 16, marginBottom: 20, flexWrap: 'wrap', alignItems: 'center' }}>
          <div style={{ display: 'inline-flex', gap: 4, padding: 4, borderRadius: 12, background: 'var(--paper-2, #f9f8ff)', border: '1px solid var(--paper-3, #e5e2f0)' }}>
            <button className="kb-btn" style={{ padding: '6px 12px', fontSize: 13 }} onClick={() => shiftWeek(-7)}>←</button>
            <button className="kb-btn" style={{ padding: '6px 14px', fontSize: 13, fontWeight: 700 }} onClick={() => setWeekStart(startOfWeek(new Date()))}>Сегодня</button>
            <button className="kb-btn" style={{ padding: '6px 12px', fontSize: 13 }} onClick={() => shiftWeek(7)}>→</button>
          </div>
          <button className="kb-btn" onClick={() => void handleGenerate()} disabled={generating} style={{ marginLeft: 'auto', background: 'var(--violet)', color: '#fff', fontWeight: 700 }}>
            {generating ? '…' : '⚡ Сгенерить слоты на эту неделю'}
          </button>
        </div>

        {loading ? (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>Загрузка…</div>
        ) : grouped.length === 0 ? (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>
            На этой неделе слотов нет. Нажмите «Сгенерить слоты», если у преподавателей настроены availability rules.
          </div>
        ) : (
          <div style={{ overflowX: 'auto' }}>
            <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 12, minWidth: 900 }}>
              <thead>
                <tr style={{ background: 'var(--paper-2, #f9f8ff)' }}>
                  <th style={{ padding: 10, textAlign: 'left', minWidth: 160, fontWeight: 700, position: 'sticky', left: 0, background: 'var(--paper-2, #f9f8ff)' }}>Преподаватель</th>
                  {DAYS.map((day, i) => {
                    const date = new Date(weekStart)
                    date.setDate(date.getDate() + i)
                    return (
                      <th key={day} style={{ padding: 10, textAlign: 'center', minWidth: 120, fontWeight: 700 }}>
                        {day}
                        <div style={{ fontSize: 11, color: 'var(--ink-soft)', fontWeight: 400 }}>
                          {date.toLocaleDateString('ru-RU', { day: 'numeric', month: 'short' })}
                        </div>
                      </th>
                    )
                  })}
                </tr>
              </thead>
              <tbody>
                {grouped.map(([teacherId, daysMap]) => (
                  <tr key={teacherId} style={{ borderTop: '1px solid var(--paper-3, #e5e2f0)' }}>
                    <td style={{ padding: 10, fontFamily: 'monospace', fontSize: 11, color: 'var(--ink-soft)', position: 'sticky', left: 0, background: '#fff', borderRight: '1px solid var(--paper-3, #e5e2f0)' }}>
                      {teacherId.slice(0, 8)}…
                    </td>
                    {DAYS.map((_, dayIdx) => {
                      const cellSlots = (daysMap.get(dayIdx) ?? []).sort((a, b) => new Date(a.datetime).getTime() - new Date(b.datetime).getTime())
                      return (
                        <td key={dayIdx} style={{ padding: 4, verticalAlign: 'top', borderLeft: '1px solid var(--paper-3, #e5e2f0)' }}>
                          {cellSlots.length === 0 ? (
                            <div style={{ minHeight: 32 }} />
                          ) : (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
                              {cellSlots.map((s) => {
                                const time = new Date(s.datetime).toLocaleTimeString('ru-RU', { hour: '2-digit', minute: '2-digit' })
                                const taken = !!s.studentId
                                return (
                                  <button
                                    key={s.id}
                                    onClick={() => setActive(s)}
                                    style={{
                                      padding: '4px 8px', borderRadius: 6, fontSize: 11,
                                      background: STATUS_COLOR[s.status] ?? '#eee',
                                      border: 'none', cursor: 'pointer', textAlign: 'left',
                                      opacity: taken ? 1 : 0.6,
                                      fontWeight: taken ? 700 : 500,
                                    }}
                                  >
                                    {time}
                                    {taken && <span style={{ marginLeft: 4 }}>👤</span>}
                                  </button>
                                )
                              })}
                            </div>
                          )}
                        </td>
                      )
                    })}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* Slot detail popover */}
        {active && (
          <div onClick={() => setActive(null)} style={{ position: 'fixed', inset: 0, zIndex: 1000, background: 'rgba(0,0,0,0.4)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 20 }}>
            <div onClick={(e) => e.stopPropagation()} className="kb-card" style={{ padding: 24, maxWidth: 480, width: '100%' }}>
              <h3 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>
                {new Date(active.datetime).toLocaleString('ru-RU', { weekday: 'long', day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })}
              </h3>
              <div style={{ marginTop: 12, fontSize: 14, lineHeight: 1.7 }}>
                <div>Длительность: {active.durationMin} мин</div>
                <div>Тип: {active.type === 'trial' ? 'Пробный' : active.type === 'makeup' ? 'Отработка' : 'Обычный'}</div>
                <div>Статус: {active.status}</div>
                <div>Преподаватель: <code>{active.teacherId.slice(0, 8)}</code></div>
                <div>Ученик: {active.studentId ? <code>{active.studentId.slice(0, 8)}</code> : '— свободен'}</div>
                {active.zoomLink && <div><a href={active.zoomLink} target="_blank" rel="noreferrer">→ Войти на занятие</a></div>}
                {active.notes && <div>Заметка: {active.notes}</div>}
              </div>
              <div style={{ display: 'flex', gap: 8, marginTop: 20, justifyContent: 'flex-end' }}>
                <button className="kb-btn" onClick={() => setActive(null)}>Закрыть</button>
                {active.status === 'scheduled' && (
                  <button className="kb-btn" style={{ background: '#dc2626', color: '#fff' }} onClick={() => void handleCancel(active)}>
                    Отменить слот
                  </button>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </PlatformShell>
  )
}
